import warnings
import os, sys
import logging
import faulthandler
faulthandler.enable()  # Print C-level stack traces on crash (SIGSEGV etc.)
logger = logging.getLogger(__name__)

# Disable OpenBLAS/OMP internal threading — must be set before numpy is imported.
# Without this, OpenBLAS spawns its own thread pool from inside a Python background
# thread, which conflicts with Python's GIL and can cause segfaults during refinement.
os.environ.setdefault("OPENBLAS_NUM_THREADS", "1")
os.environ.setdefault("OMP_NUM_THREADS", "1")
os.environ.setdefault("MKL_NUM_THREADS", "1")

# Set up bundled GTK/GI paths on Windows before any GTK imports
if sys.platform == "win32":
    # Derive the bundle root from this file's location:
    # core.py lives in <root>/lib/python3.14/site-packages/mudlab/
    _pkg_dir  = os.path.dirname(os.path.abspath(__file__))
    _root     = os.path.normpath(os.path.join(_pkg_dir, "..", "..", "..", "..", ".."))
    _bin_dir  = os.path.join(_root, "bin")
    _lib_dir  = os.path.join(_root, "lib")

    # Register the bin dir so Windows can find GTK DLLs from .pyd files
    if os.path.isdir(_bin_dir):
        os.add_dll_directory(_bin_dir)
        os.environ["PATH"] = _bin_dir + os.pathsep + os.environ.get("PATH", "")

    # Point GI to our bundled typelibs
    _typelib_dir = os.path.join(_lib_dir, "girepository-1.0")
    if os.path.isdir(_typelib_dir):
        os.environ["GI_TYPELIB_PATH"] = _typelib_dir

    # Point GDK-Pixbuf to our bundled loaders
    _pixbuf_dir  = os.path.join(_lib_dir, "gdk-pixbuf-2.0", "2.10.0", "loaders")
    _pixbuf_cache = os.path.join(_lib_dir, "gdk-pixbuf-2.0", "2.10.0", "loaders.cache")
    if os.path.isdir(_pixbuf_dir):
        os.environ["GDK_PIXBUF_MODULEDIR"] = _pixbuf_dir
    if os.path.isfile(_pixbuf_cache):
        os.environ["GDK_PIXBUF_MODULE_FILE"] = _pixbuf_cache

    # Suppress GLib-GIO D-Bus warning on Windows (gdbus.exe not present)
    os.environ.setdefault("GIO_USE_VFS", "local")

from mvc.support.gui_loop import start_event_loop

def _run_user_script():
    """
        Runs the user script specified in the command-line arguments.
    """
    from mudlab.data import settings

    try:
        import importlib.util
        spec = importlib.util.spec_from_file_location('user_script', settings.ARGS.script)
        user_script = importlib.util.module_from_spec(spec)
        spec.loader.exec_module(user_script)
    except BaseException as err:
        err.args = "Error when trying to import %s: %s" % (settings.ARGS.script, err.args)
        raise
    user_script.run(settings.ARGS)

def _run_gui(project=None):

    # Display a splash screen showing the loading status...
    import importlib.resources
    from mudlab.application.splash import SplashScreen
    from mudlab import __version__

    filename = str(importlib.resources.files(__name__).joinpath("application/icons/mudlab.png"))
    splash = SplashScreen(filename, __version__)

    # Run GUI:
    splash.set_message("Loading ...")

    # Now we can load these:
    from mudlab.data import settings
    from mudlab.file_parsers.json_parser import JSONParser
    from mudlab.application.models import AppModel
    from mudlab.application.views import AppView
    from mudlab.application.controllers import AppController
    
    # TODO move this to mvc:
    from mudlab.generic.gtk_tools.gtkexcepthook import plugin_gtk_exception_hook

    filename = settings.ARGS.filename #@UndefinedVariable

    # Check if a filename was passed, if so try to load it
    if filename != "":
        try:
            logging.info("Opening project: %s" % filename)
            project = JSONParser.parse(filename)
        except IOError:
            logging.info("Could not load project file %s: IOError" % filename)
            # FIXME the user should be informed of this in a dialog...

    if not settings.DEBUG:
        warnings.filterwarnings(action='ignore', category=Warning)

    # Close splash screen
    if splash: 
        splash.close()

    # Nice GUI error handler:
    gtk_exception_hook = plugin_gtk_exception_hook()

    # setup MVC:
    m = AppModel(project=project)
    v = AppView()
    AppController(m, v, gtk_exception_hook=gtk_exception_hook)

    # Free this before continuing
    del splash

    # lets get this show on the road:
    start_event_loop()

def run_main():
    """
        Parsers command line arguments and launches MudLab accordingly.
    """

    # Make sure the current path is used for loading MudLab modules:
    mod = os.path.dirname(os.path.dirname(os.path.abspath(__file__)))
    if not mod in sys.path:
        sys.path.insert(1, mod)

    # Init settings, first import will trigger initialization
    from mudlab.data import settings
    settings.initialize()

    # Setup basic logging
    from mudlab.logs import setup_logging
    setup_logging(basic=True)

    if settings.DEBUG:
        from mudlab import stacktracer
        stacktracer.trace_start(
            "trace.html",
            interval=5, auto=True) # Set auto flag to always update file!

    try:
        if settings.ARGS.script:
            # Run the specified user script:
            _run_user_script()
        else:
            # Run the GUI:
            _run_gui()
    except:
        raise # re-raise the error
    finally:
        for finalizer in settings.FINALIZERS:
            finalizer()
        if settings.DEBUG: stacktracer.trace_stop()

if __name__ == "__main__":
    run_main()
